const body = $input.item.json.body;
const required = ['doc_type', 'doc_number', 'item_code', 'quantity', 'performed_by', 'action'];
const missing = required.filter(f => body[f] === undefined || body[f] === null || body[f] === '');
if (missing.length > 0) {
  return { json: { _error: true, success: false, message: '缺少字段: ' + missing.join(', ') } };
}
const qty = parseFloat(body.quantity);
if (isNaN(qty)) {
  return { json: { _error: true, success: false, message: '数量无效' } };
}
if (body.action !== 'count' && qty <= 0) {
  return { json: { _error: true, success: false, message: '数量必须大于0' } };
}
return { json: {
  _error: false,
  doc_type: body.doc_type,
  doc_number: String(body.doc_number),
  sap_doc_num: String(body.sap_doc_num || body.doc_number),
  sap_doc_entry: body.sap_doc_entry || null,
  item_code: String(body.item_code),
  item_name: String(body.item_name || ''),
  quantity: qty,
  warehouse_code: String(body.warehouse_code || ''),
  bin_location: body.bin_location || null,
  from_warehouse: body.from_warehouse || null,
  from_bin: body.from_bin || null,
  line_num: body.line_num !== undefined ? parseInt(body.line_num) : -1,
  performed_by: String(body.performed_by),
  action: String(body.action),
  remarks: String(body.remarks || ''),
  planned_qty: parseFloat(body.planned_qty) || 0,
  uom: String(body.uom || ''),
  batch_number: body.batch_number ? String(body.batch_number) : null,
  production_date: body.production_date ? String(body.production_date) : null,
  transaction_time: body.transaction_time ? String(body.transaction_time) : null
}};

const docId = $input.item.json.id;
const prev = $('Validate').first().json;
return { json: { ...prev, document_id: docId } };

const lineId = $input.item.json.id;
const prev = $('Merge Doc ID').first().json;
return { json: { ...prev, line_id: lineId } };
